function createCharacter(row, index) {
  return {
    id: index + 1,
    hanzi: row[0],
    pinyin: row[1],
    strokes: row[2],
    word: row[3],
    meaning: row[4],
    writingTip: row[5],
    memoryTip: row[6],
    status: row[7]
  };
}

window.CHINESE_GAME_DATA = Array.from({ length: 125 }, (_, levelIndex) => {
  const levelRows = characterRows.slice(
    levelIndex * 20,
    (levelIndex + 1) * 20
  );

  return {
    id: levelIndex + 1,
    title: `第 ${levelIndex + 1} 关 · ${levelNames[levelIndex]}`,
    subtitle: "本关包含 20 个常用字，全部会认后就能开宝箱。",
    targetCount: 20,
    characters: levelRows.map((row, rowIndex) => createCharacter(
      row,
      levelIndex * 20 + rowIndex
    ))
  };
});
